public struct AiInterpretation {
    public var chunks: [String]
    public var usedFallback: Bool

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(chunks: [String], usedFallback: Bool) {
        self.chunks = chunks
        self.usedFallback = usedFallback
    }
}


extension AiInterpretation: Equatable, Hashable {
    public static func ==(lhs: AiInterpretation, rhs: AiInterpretation) -> Bool {
        if lhs.chunks != rhs.chunks {
            return false
        }
        if lhs.usedFallback != rhs.usedFallback {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(chunks)
        hasher.combine(usedFallback)
    }
}


