// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
public enum UserIntent {
    
    case clarity
    case comfort
    case challenge
    case guidance
}

public struct FfiConverterTypeUserIntent: FfiConverterRustBuffer {
    typealias SwiftType = UserIntent

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> UserIntent {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .clarity
        
        case 2: return .comfort
        
        case 3: return .challenge
        
        case 4: return .guidance
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: UserIntent, into buf: inout [UInt8]) {
        switch value {
        
        
        case .clarity:
            writeInt(&buf, Int32(1))
        
        
        case .comfort:
            writeInt(&buf, Int32(2))
        
        
        case .challenge:
            writeInt(&buf, Int32(3))
        
        
        case .guidance:
            writeInt(&buf, Int32(4))
        
        }
    }
}


public func FfiConverterTypeUserIntent_lift(_ buf: RustBuffer) throws -> UserIntent {
    return try FfiConverterTypeUserIntent.lift(buf)
}

public func FfiConverterTypeUserIntent_lower(_ value: UserIntent) -> RustBuffer {
    return FfiConverterTypeUserIntent.lower(value)
}


extension UserIntent: Equatable, Hashable {}



